class Solution {
public:
    int countKDifference(vector<int>& nums, int k) {
        unordered_map<int, int> countMap;
        int result = 0;
        for (int num : nums) {
            result += countMap[num - k] + countMap[num + k];
            countMap[num]++;
        }
        return result;
    }
};
